#!/usr/bin/env bash
# Generated by bun-bench Harbor export adapter. Oracle reference solution.
# Overwrites the starter source under /app with the bun-bench reference.
set -euo pipefail

mkdir -p /app/src
cat > /app/src/server.ts <<'BUN_BENCH_SOLUTION_EOF'
const port = Number(Bun.env.PORT ?? 3000);

const LIMIT = 5;
const WINDOW_MS = 1000;

// Per-client list of timestamps (ms) of previously allowed requests.
const hits = new Map<string, number[]>();

function recent(clientId: string, now: number): number[] {
  const all = hits.get(clientId) ?? [];
  // Keep only timestamps that fall within the rolling window ending at `now`.
  const cutoff = now - WINDOW_MS;
  const kept = all.filter((t) => t > cutoff);
  hits.set(clientId, kept);
  return kept;
}

Bun.serve({
  port,
  fetch(request) {
    const url = new URL(request.url);

    if (request.method === "GET" && url.pathname === "/resource") {
      const clientId = request.headers.get("x-client-id");
      if (!clientId) {
        return Response.json({ error: "missing_client_id" }, { status: 400 });
      }

      const now = Date.now();
      const window = recent(clientId, now);

      if (window.length >= LIMIT) {
        // Oldest in-window timestamp leaves the window at oldest + WINDOW_MS.
        const oldest = window[0]!;
        const msUntilFree = oldest + WINDOW_MS - now;
        const retryAfter = Math.max(1, Math.ceil(msUntilFree / 1000));
        return Response.json(
          { error: "rate_limited" },
          {
            status: 429,
            headers: {
              "Retry-After": String(retryAfter),
              "X-RateLimit-Limit": String(LIMIT),
              "X-RateLimit-Remaining": "0",
            },
          },
        );
      }

      window.push(now);
      hits.set(clientId, window);
      const remaining = LIMIT - window.length;
      return Response.json(
        { ok: true },
        {
          status: 200,
          headers: {
            "X-RateLimit-Limit": String(LIMIT),
            "X-RateLimit-Remaining": String(remaining),
          },
        },
      );
    }

    return Response.json({ error: "not_found" }, { status: 404 });
  },
});

console.log(`sliding-window reference listening on ${port}`);
BUN_BENCH_SOLUTION_EOF
